3 個 Python 進階特性—寫熟讓你從中階變高階。


### Decorator（裝飾器）

```text
# Decorator = 「包一層、加功能」

# 最簡單版
def my_decorator(func):
    def wrapper():
        print("Before")
        func()
        print("After")
    return wrapper

@my_decorator
def hello():
    print("Hello")

hello()
# Before
# Hello
# After

# 等同於：
hello = my_decorator(hello)

# 帶參數的函數
def my_decorator(func):
    def wrapper(*args, **kwargs):
        print("Before")
        result = func(*args, **kwargs)
        print("After")
        return result
    return wrapper

@my_decorator
def greet(name):
    return f"Hi, {name}"

print(greet("Alice"))

# 實戰：計時
import time
from functools import wraps

def timing(func):
    @wraps(func)   # 保留原 function 的 metadata
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        print(f"{func.__name__} 花了 {time.time() - start:.2f}s")
        return result
    return wrapper

@timing
def slow_function():
    time.sleep(1)
    return "完成"

slow_function()
# slow_function 花了 1.00s

# 實戰：log
def log_calls(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        print(f"Calling {func.__name__}({args}, {kwargs})")
        return func(*args, **kwargs)
    return wrapper

@log_calls
def add(a, b):
    return a + b

# 帶參數的 decorator
def retry(max_attempts=3):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            for attempt in range(max_attempts):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    if attempt == max_attempts - 1:
                        raise
                    time.sleep(2 ** attempt)
        return wrapper
    return decorator

@retry(max_attempts=5)
def flaky_api_call():
    ...

# 內建 decorator
@property            # getter
@staticmethod        # 靜態方法
@classmethod         # 類別方法
@dataclass           # 自動產生 __init__ 等

# Library 提供
@app.route("/users") # Flask
@app.get("/users")   # FastAPI
@cache               # functools.cache
@lru_cache           # functools.lru_cache
@pytest.fixture      # pytest
```


